import { InlineKeyboard } from "grammy";
import { safeErr } from "../lib/safe.js";
import { getWatchlist, removeFromWatchlist, addToWatchlist } from "../stores/watchlists.js";
import { getTokenMetrics } from "../services/solanaData.js";
import { scoreToken } from "../services/scoring.js";

function fmtUsd(v) {
  if (v === null || v === undefined) return "n/a";
  const n = Number(v);
  if (!Number.isFinite(n)) return "n/a";
  if (n >= 1e6) return "$" + (n / 1e6).toFixed(2) + "M";
  if (n >= 1e3) return "$" + (n / 1e3).toFixed(1) + "K";
  return "$" + n.toFixed(2);
}

export function registerWatchlist(bot, { cfg, cache }) {
  bot.command("watchlist", async (ctx) => {
    const userId = ctx.from?.id;
    if (!userId) return;

    const wl = await getWatchlist(cfg, userId);
    const items = Array.isArray(wl.items) ? wl.items : [];

    if (items.length === 0) {
      return ctx.reply("Your watchlist is empty. Use Add to watchlist from /scan or /token.");
    }

    await ctx.reply("Your watchlist (" + items.length + "):");

    for (const it of items.slice(0, 25)) {
      const mint = String(it.mintAddress);
      const ckey = "token:" + mint;
      let m = cache?.get(ckey);
      if (!m) {
        m = await getTokenMetrics(mint);
        cache?.set(ckey, m, 30_000);
      }
      const s = scoreToken(m);

      const title = (m.symbol ? m.symbol + " " : "") + (m.name || "Token");
      const msg = [
        title,
        "Mint: " + mint,
        "Score: " + s.score + "  Liq: " + fmtUsd(m.liquidityUsd) + "  Vol24h: " + fmtUsd(m.volume24hUsd),
      ].join("\n");

      const kb = new InlineKeyboard()
        .text("Details", "token:show:" + mint)
        .text("Remove", "watch:remove:" + mint);

      await ctx.reply(msg, { reply_markup: kb, disable_web_page_preview: true });
    }

    if (items.length > 25) {
      await ctx.reply("Showing first 25 items.");
    }
  });

  bot.on("message:text", async (ctx, next) => {
    // Allow adding by replying with a mint address if the user is in watchlist context.
    // Minimal implementation: detect plain mint-like strings and offer quick add.
    const t = String(ctx.message?.text || "").trim();
    if (t.startsWith("/")) return next();

    if (t.length < 32 || t.length > 60) return next();
    if (!/^[1-9A-HJ-NP-Za-km-z]+$/.test(t)) return next();

    const userId = ctx.from?.id;
    if (!userId) return next();

    const kb = new InlineKeyboard().text("Add to watchlist", "watch:add:" + t);
    return ctx.reply("That looks like a mint address. Add it to your watchlist?", { reply_markup: kb });
  });

  bot.on("callback_query:data", async (ctx, next) => {
    const data = ctx.callbackQuery?.data || "";
    if (!String(data).startsWith("watch:remove:")) return next();

    const userId = ctx.from?.id;
    if (!userId) return;

    const mint = String(data).split(":").pop();

    try {
      await removeFromWatchlist(cfg, userId, mint);
      await ctx.answerCallbackQuery("Removed");
      return ctx.reply("Removed from watchlist.");
    } catch (e) {
      console.warn("[watchlist] remove failed", { err: safeErr(e) });
      await ctx.answerCallbackQuery();
      return ctx.reply("Could not remove.");
    }
  });

  bot.on("callback_query:data", async (ctx, next) => {
    const data = ctx.callbackQuery?.data || "";
    if (!String(data).startsWith("watch:add:")) return next();

    const userId = ctx.from?.id;
    if (!userId) return;

    const mint = String(data).split(":").pop();

    const r = await addToWatchlist(cfg, userId, mint);
    await ctx.answerCallbackQuery();
    if (!r.ok) return ctx.reply("Could not add to watchlist. Set MONGODB_URI for persistence.");
    return ctx.reply("Added to watchlist.");
  });
}

index.js.content:
import "dotenv/config";

import { run } from "@grammyjs/runner";

import { cfg } from "./lib/config.js";
import { safeErr, sleep } from "./lib/safe.js";
import { createBot } from "./bot.js";
import { registerCommands } from "./commands/loader.js";
import { createTtlCache } from "./services/cache.js";
import { startAlertsLoop } from "./services/alertsEngine.js";

process.on("unhandledRejection", (r) => {
  console.error("UnhandledRejection:", safeErr(r));
  process.exit(1);
});
process.on("uncaughtException", (e) => {
  console.error("UncaughtException:", safeErr(e));
  process.exit(1);
});

async function boot() {
  console.log("[boot] start", {
    nodeEnv: cfg.NODE_ENV,
    TELEGRAM_BOT_TOKEN_set: !!cfg.TELEGRAM_BOT_TOKEN,
    MONGODB_URI_set: !!cfg.MONGODB_URI,
    COOKMYBOTS_AI_ENDPOINT_set: !!cfg.COOKMYBOTS_AI_ENDPOINT,
    COOKMYBOTS_AI_KEY_set: !!cfg.COOKMYBOTS_AI_KEY,
  });

  if (!cfg.TELEGRAM_BOT_TOKEN) {
    console.error("TELEGRAM_BOT_TOKEN is required. Set it in the environment and redeploy.");
    process.exit(1);
  }

  const bot = createBot(cfg.TELEGRAM_BOT_TOKEN);

  // Global cache handle for admin refresh
  const globalCache = createTtlCache({ max: 3000 });
  bot._globalCache = globalCache;

  // Init bot info early so ctx.me works
  try {
    await bot.init();
  } catch (e) {
    console.warn("[boot] bot.init failed", { err: safeErr(e) });
  }

  await registerCommands(bot);

  try {
    await bot.api.setMyCommands([
      { command: "start", description: "Welcome and main actions" },
      { command: "help", description: "How to use the bot" },
      { command: "scan", description: "Scan recent tokens" },
      { command: "token", description: "Token details by mint address" },
      { command: "watchlist", description: "View your watchlist" },
      { command: "alerts", description: "Manage alerts" },
      { command: "admin", description: "Admin tools" },
      { command: "reset", description: "Clear AI memory" },
    ]);
  } catch (e) {
    console.warn("[boot] setMyCommands failed", { err: safeErr(e) });
  }

  // Alerts loop
  let alertsRunning = false;
  bot._alertsLoopRunning = false;
  startAlertsLoop({
    bot,
    cfg,
    cache: globalCache,
    setRunningFlag(v) {
      alertsRunning = !!v;
      bot._alertsLoopRunning = !!v;
    },
  });

  // Polling with runner, with deleteWebhook and 409 backoff safety
  console.log("[boot] polling start");

  let backoffMs = 2000;
  while (true) {
    try {
      await bot.api.deleteWebhook({ drop_pending_updates: true });

      const runner = run(bot, {
        concurrency: 1,
      });

      await runner.task();

      // runner.task() resolves only when stopped; restart loop
      console.warn("[boot] runner stopped; restarting", { backoffMs });
    } catch (e) {
      const msg = safeErr(e);
      console.warn("[boot] polling error", { err: msg });

      if (String(msg).includes("409") || String(msg).toLowerCase().includes("conflict")) {
        console.warn("[boot] getUpdates conflict; backing off", { backoffMs });
      }
    }

    await sleep(backoffMs);
    backoffMs = Math.min(20_000, Math.round(backoffMs * 1.7));
  }
}

boot().catch((e) => {
  console.error("[boot] fatal", { err: safeErr(e) });
  process.exit(1);
});

