import { safeErr, sleep } from "../lib/safe.js";
import { listEnabledAlerts, touchAlertTriggered } from "../stores/alerts.js";
import { getTokenMetrics } from "./solanaData.js";
import { scoreToken } from "./scoring.js";

function shouldTrigger(alert, metrics) {
  const type = String(alert?.type || "");
  const p = alert?.params || {};

  if (type === "price_change_pct") {
    // Stub: without historical candles, we cannot compute real change.
    // For now, never trigger.
    return false;
  }

  if (type === "liquidity_drop_pct") {
    return false;
  }

  if (type === "volume_spike_pct") {
    return false;
  }

  // If unknown type: do nothing.
  return false;
}

export function startAlertsLoop({ bot, cfg, cache, setRunningFlag }) {
  let stopped = false;

  async function loop() {
    console.log("[alerts] poll started", { intervalSeconds: cfg.ALERTS_POLL_INTERVAL_SECONDS });

    let cycles = 0;

    while (!stopped) {
      const cycleStarted = Date.now();
      cycles++;

      try {
        setRunningFlag?.(true);

        const alerts = await listEnabledAlerts(cfg);
        const uniqueTokens = new Set(alerts.map((a) => String(a.mintAddress || "")).filter(Boolean));

        let checked = 0;
        let triggered = 0;

        for (const mintAddress of uniqueTokens) {
          checked++;

          // Cache token metrics briefly during this cycle.
          const ckey = "metrics:" + mintAddress;
          let metrics = cache?.get(ckey);
          if (!metrics) {
            metrics = await getTokenMetrics(mintAddress);
            cache?.set(ckey, metrics, 30_000);
          }

          // Evaluate each alert for this token.
          const tokenAlerts = alerts.filter((a) => String(a.mintAddress) === String(mintAddress));
          for (const a of tokenAlerts) {
            const ok = shouldTrigger(a, metrics);
            if (!ok) continue;

            triggered++;
            await touchAlertTriggered(cfg, a._id);

            // Send notification
            try {
              const s = scoreToken(metrics);
              const msg = [
                "Alert triggered for " + (metrics.symbol || metrics.name || mintAddress),
                "Mint: " + mintAddress,
                "Score: " + s.score,
              ].join("\n");
              await bot.api.sendMessage(Number(a.telegramUserId), msg);
            } catch (e) {
              console.warn("[alerts] send fail", { err: safeErr(e) });
            }
          }
        }

        console.log("[alerts] cycle", {
          ms: Date.now() - cycleStarted,
          alerts: alerts.length,
          tokensChecked: checked,
          triggered,
        });

        // Memory log once per minute-ish
        if (cycles % Math.max(1, Math.round(60 / cfg.ALERTS_POLL_INTERVAL_SECONDS)) === 0) {
          const m = process.memoryUsage();
          console.log("[mem]", {
            rssMB: Math.round(m.rss / 1e6),
            heapUsedMB: Math.round(m.heapUsed / 1e6),
          });
        }
      } catch (e) {
        console.warn("[alerts] cycle fail", { err: safeErr(e) });
      } finally {
        setRunningFlag?.(true);
      }

      const sleepMs = Math.max(500, cfg.ALERTS_POLL_INTERVAL_SECONDS * 1000 - (Date.now() - cycleStarted));
      await sleep(sleepMs);
    }
  }

  loop();

  return {
    stop() {
      stopped = true;
    },
  };
}

cache.js.content:
import { safeErr } from "../lib/safe.js";

export function createTtlCache({ max = 2000 } = {}) {
  const map = new Map();

  function prune() {
    if (map.size <= max) return;
    const n = Math.ceil(max * 0.1);
    const keys = map.keys();
    for (let i = 0; i < n; i++) {
      const k = keys.next().value;
      if (k === undefined) break;
      map.delete(k);
    }
  }

  return {
    get(key) {
      try {
        const v = map.get(key);
        if (!v) return null;
        if (v.expiresAt && Date.now() > v.expiresAt) {
          map.delete(key);
          return null;
        }
        return v.value;
      } catch (e) {
        console.warn("[cache] get failed", { err: safeErr(e) });
        return null;
      }
    },
    set(key, value, ttlMs = 30_000) {
      try {
        map.set(key, {
          value,
          expiresAt: ttlMs > 0 ? Date.now() + ttlMs : 0,
        });
        prune();
      } catch (e) {
        console.warn("[cache] set failed", { err: safeErr(e) });
      }
    },
    del(key) {
      map.delete(key);
    },
    clear() {
      map.clear();
    },
    size() {
      return map.size;
    },
  };
}

scoring.js.content:
import { clampNumber } from "../lib/safe.js";

export function scoreToken(m) {
  const breakdown = {};

  const liquidity = clampNumber(m?.liquidityUsd, { min: 0, max: 1e12, fallback: 0 });
  const volume24h = clampNumber(m?.volume24hUsd, { min: 0, max: 1e12, fallback: 0 });
  const ageMinutes = clampNumber(m?.ageMinutes, { min: 0, max: 1e9, fallback: 0 });
  const holders = clampNumber(m?.holderCount, { min: 0, max: 1e9, fallback: 0 });
  const top10Pct = clampNumber(m?.top10HolderPct, { min: 0, max: 100, fallback: 0 });

  const mintDisabled = m?.mintAuthorityDisabled === true;
  const freezeDisabled = m?.freezeAuthorityDisabled === true;

  breakdown.liquidity = Math.round(Math.min(30, Math.log10(liquidity + 1) * 10));
  breakdown.volume24h = Math.round(Math.min(25, Math.log10(volume24h + 1) * 8));

  const ageScore = ageMinutes <= 30 ? 2 : ageMinutes <= 120 ? 6 : ageMinutes <= 1440 ? 10 : 8;
  breakdown.age = ageScore;

  breakdown.holders = Math.round(Math.min(15, Math.log10(holders + 1) * 5));

  const concPenalty = top10Pct >= 80 ? -18 : top10Pct >= 65 ? -12 : top10Pct >= 50 ? -6 : 0;
  breakdown.concentration = concPenalty;

  breakdown.authorities = (mintDisabled ? 5 : -6) + (freezeDisabled ? 5 : -6);

  const total = Object.values(breakdown).reduce((a, b) => a + b, 0);
  const score = Math.max(0, Math.min(100, Math.round(total)));

  const flags = [];
  if (!mintDisabled) flags.push("mint on");
  if (!freezeDisabled) flags.push("freeze on");
  if (top10Pct >= 65) flags.push("top10 " + Math.round(top10Pct) + "%");
  if (liquidity > 0 && liquidity < 10_000) flags.push("low liq");
  if (holders > 0 && holders < 100) flags.push("few holders");

  return { score, breakdown, flags };
}

